import hashlib, uuid
from dataclasses import dataclass, field
from datetime import datetime, timezone
from enum import IntEnum
from typing import Optional

class DataTier(IntEnum):
    PUBLIC = 1
    INTERNAL = 2
    CONFIDENTIAL = 3
    RESTRICTED = 4

@dataclass
class ChunkProvenance:
    chunk_id: str
    source_doc_id: str
    source_doc_version: str
    source_location: str  # e.g. "page:12" or "section:3.2"
    similarity_score: float
    data_tier: DataTier
    chunk_hash: str

    @classmethod
    def from_chunk(
        cls, chunk_id: str, content: str,
        metadata: dict, similarity_score: float,
    ) -> "ChunkProvenance":
        chunk_hash = hashlib.sha256(content.encode()).hexdigest()
        return cls(
            chunk_id=chunk_id,
            source_doc_id=metadata["source_doc_id"],
            source_doc_version=metadata.get("version", "unknown"),
            source_location=metadata.get("location", ""),
            similarity_score=round(similarity_score, 4),
            data_tier=DataTier(metadata.get("tier", DataTier.INTERNAL)),
            chunk_hash=chunk_hash,
        )

    @property
    def citation(self) -> str:
        """Human-readable citation string."""
        return f"{self.source_doc_id} v{self.source_doc_version} ({self.source_location})"

@dataclass
class RetrievalProvenanceRecord:
    retrieval_id: str = field(default_factory=lambda: str(uuid.uuid4()))
    lineage_id: str = ""
    query_hash: str = ""
    index_id: str = ""
    index_version: str = ""
    retrieved_chunks: list[ChunkProvenance] = field(default_factory=list)
    retrieval_latency_ms: float = 0.0
    timestamp_utc: str = field(
        default_factory=lambda: datetime.now(timezone.utc).isoformat()
    )

    @property
    def max_data_tier(self) -> DataTier:
        if not self.retrieved_chunks:
            return DataTier.PUBLIC
        return max(c.data_tier for c in self.retrieved_chunks)

    @property
    def citations(self) -> list[str]:
        return [c.citation for c in self.retrieved_chunks]

def record_retrieval_provenance(
    query: str,
    raw_results: list[dict],  # Each: {"id", "content", "metadata", "score"}
    lineage_id: str,
    index_id: str,
    index_version: str,
    latency_ms: float,
) -> RetrievalProvenanceRecord:
    """Build a provenance record from raw vector search results."""
    query_hash = hashlib.sha256(query.encode()).hexdigest()
    chunks = [
        ChunkProvenance.from_chunk(
            r["id"], r["content"], r["metadata"], r["score"]
        )
        for r in raw_results
    ]
    record = RetrievalProvenanceRecord(
        lineage_id=lineage_id,
        query_hash=query_hash,
        index_id=index_id,
        index_version=index_version,
        retrieved_chunks=chunks,
        retrieval_latency_ms=latency_ms,
    )
    return record

# Simulated retrieval results
raw_results = [
    {
        "id": "chk-001",
        "content": "The annual performance review process consists of three stages...",
        "metadata": {
            "source_doc_id": "policy-doc-v3.pdf",
            "version": "3.0",
            "location": "page:12",
            "tier": 2,
        },
        "score": 0.92,
    },
    {
        "id": "chk-002",
        "content": "Base salary adjustments following review are capped at...",
        "metadata": {
            "source_doc_id": "contract-23-B.docx",
            "version": "2024-01-15",
            "location": "page:4",
            "tier": 3,
        },
        "score": 0.88,
    },
]

prov = record_retrieval_provenance(
    query="What is the performance review process?",
    raw_results=raw_results,
    lineage_id="lnx-0023",
    index_id="kb-v4",
    index_version="2024-07-01",
    latency_ms=145.2,
)

print(f"Max tier: {prov.max_data_tier.name}")
print("Citations:")
for c in prov.citations:
    print(f"  - {c}")
